import type { AlgorithmNode, AlgorithmTree, ContentBlock, NodeType } from "../types/algorithm";

function blocks(...items: string[]): ContentBlock[] {
  return items.map((text) => ({ text }));
}

function node(entry: AlgorithmNode): AlgorithmNode {
  return entry;
}

function terminal(
  id: string,
  title: string,
  type: Extract<NodeType, "diagnosis" | "morphologic_terminal" | "placeholder">,
  parentId: string,
  description: string,
  notes?: ContentBlock[],
  tags?: string[],
  synonyms?: string[],
): AlgorithmNode {
  return { id, title, type, parentId, description, notes, tags, synonyms, result: { title, summary: description } };
}

function diagnosisGroup(
  id: string,
  title: string,
  parentId: string,
  description: string,
  possibilities: string[],
  notes?: ContentBlock[],
  tags?: string[],
  synonyms?: string[],
): AlgorithmNode {
  return { id, title, type: "diagnosis", parentId, description, notes, tags, synonyms, result: { title, summary: description, possibilities } };
}

function annexialDiagnosis(
  id: string,
  title: string,
  parentId: string,
  tags: string[] = [],
  synonyms: string[] = [],
): AlgorithmNode {
  return terminal(
    id,
    title,
    "diagnosis",
    parentId,
    "Diagnóstico anexial dentro do ramo neoplásico.",
    blocks("Diagnóstico anexial dentro do ramo neoplásico."),
    tags,
    synonyms,
  );
}

function epidermalDiagnosis(
  id: string,
  title: string,
  parentId: string,
  description: string,
  tags: string[] = [],
  synonyms: string[] = [],
): AlgorithmNode {
  return terminal(id, title, "diagnosis", parentId, description, blocks(description), tags, synonyms);
}

